package main

import (
    "encoding/json"
    "os"
    "reflect"
    "sort"
)

type entry struct {
    Case      string `json:"case"`
    Produced  []int  `json:"produced"`
    Trace     []int  `json:"slot_trace"`
    OrderUsed []int  `json:"order_used"`
    Packed    bool   `json:"packed"`
    Grouped   bool   `json:"grouped"`
    Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
    Raw []entry `json:"raw"`
}

type finalDoc struct {
    Rows    []entry        `json:"rows"`
    Summary map[string]any `json:"summary"`
}

func sortByCase(a []entry) {
    sort.Slice(a, func(i, j int) bool { return a[i].Case < a[j].Case })
}

func toMap(a []entry) map[string]entry {
    m := make(map[string]entry, len(a))
    for _, r := range a {
        m[r.Case] = r
    }
    return m
}

func sameSix(a, b entry) bool {
    if a.Case != b.Case {
        return false
    }
    if a.Packed != b.Packed || a.Grouped != b.Grouped || a.Reuse != b.Reuse {
        return false
    }
    if !reflect.DeepEqual(a.Produced, b.Produced) {
        return false
    }
    if !reflect.DeepEqual(a.Trace, b.Trace) {
        return false
    }
    if !reflect.DeepEqual(a.OrderUsed, b.OrderUsed) {
        return false
    }
    return true
}

func agreeOnAll(raw []entry, report []entry) bool {
    if len(raw) != len(report) {
        return false
    }
    rm := toMap(raw)
    pm := toMap(report)
    if len(rm) != len(raw) || len(pm) != len(report) {
        // duplicates by case name present
        return false
    }
    for name, r := range rm {
        p, ok := pm[name]
        if !ok {
            return false
        }
        if !sameSix(r, p) {
            return false
        }
    }
    // also ensure no extras in report
    for name := range pm {
        if _, ok := rm[name]; !ok {
            return false
        }
    }
    return true
}

func readJSON(path string, v any) error {
    b, err := os.ReadFile(path)
    if err != nil {
        return err
    }
    return json.Unmarshal(b, v)
}

func main() {
    if len(os.Args) != 3 {
        panic("usage: align raw final")
    }
    rawPath := os.Args[1]
    finalPath := os.Args[2]

    var raw rawDoc
    if err := readJSON(rawPath, &raw); err != nil {
        panic(err)
    }

    // rows are the raw entries (1 per built-in case), sorted deterministically.
    rows := append([]entry(nil), raw.Raw...)
    sortByCase(rows)

    agree := agreeOnAll(raw.Raw, rows)

    // Additional requirement: when replacing an existing finalPath, compare
    // incoming raw rows against the report rows already stored there.
    if _, err := os.Stat(finalPath); err == nil {
        var prior finalDoc
        if err := readJSON(finalPath, &prior); err != nil {
            // If prior is unreadable, must not claim agreement.
            agree = false
        } else {
            if !agreeOnAll(raw.Raw, prior.Rows) {
                agree = false
            }
        }
    }

    doc := finalDoc{Rows: rows, Summary: map[string]any{"total": len(raw.Raw), "agree": agree}}
    out, err := json.MarshalIndent(doc, "", "  ")
    if err != nil {
        panic(err)
    }
    if err := os.WriteFile(finalPath, append(out, '\n'), 0o644); err != nil {
        panic(err)
    }
}
